20	// syncBuffer is a concurrency-safe bytes.Buffer (mirrors internal/device's test
21	// helper of the same name) so a logger write from under m.mu never races the
22	// test's read of the captured JSON log text.
23	type syncBuffer struct {
24		mu  sync.Mutex
25		buf bytes.Buffer
26	}
27	
28	func (b *syncBuffer) Write(p []byte) (int, error) {
29		b.mu.Lock()
30		defer b.mu.Unlock()
31		return b.buf.Write(p)
32	}
33	
34	func (b *syncBuffer) String() string {
35		b.mu.Lock()
36		defer b.mu.Unlock()
37		return b.buf.String()
38	}
39	
40	// newWarnCapturingMultipath builds an OPEN, runtime-path-capable Multipath (probers +
41	// newProber + a DynamicScheduler — AddPath's preconditions) whose logger writes JSON
42	// records into the returned buffer at "info" level (so the D53 AUTO-fallback
43	// informational record is captured too, not just WARN/ERROR). It is the D53 test
44	// harness: every scenario below drives AddPath/reconcileDeferred over paths[] and then
45	// inspects buf for the forced-device-bind fallback WARN.
46	func newWarnCapturingMultipath(t *testing.T, paths []config.Path, psk config.Key) (*Multipath, *syncBuffer) {
47		t.Helper()
48		buf := &syncBuffer{}
49		lg, err := log.New("info", buf)
50		if err != nil {
51			t.Fatalf("log.New: %v", err)
52		}
53		clk := telemetry.SystemClock{}
54		cfg := telemetry.ProberConfig{
55			LossWindow: 0,
56			Liveness:   telemetry.LivenessConfig{DownAfter: testProbeDownAfter, UpAfterSuccesses: testProbeUpSucc},
57		}
58		newProber := func(name string, id uint8) *telemetry.Prober {
59			return telemetry.NewProber(name, id, testProbeSessionID, psk, cfg, clk, lg)
60		}
61		probers := make([]*telemetry.Prober, len(paths))
62		health := make([]sched.PathHealth, len(paths))
63		for i := range paths {
64			probers[i] = newProber(paths[i].Name, uint8(i))
65			health[i] = probers[i]
66		}
67		scheduler, err := sched.NewActiveBackup(health, sched.Config{FailbackAfter: time.Hour}, clk, lg)
68		if err != nil {
69			t.Fatalf("build scheduler: %v", err)
70		}
71		m, err := NewMultipath(paths, psk, scheduler, probers, newProber, nil, nil, config.Amnezia{}, lg)
72		if err != nil {
73			t.Fatalf("NewMultipath: %v", err)
74		}
75		if _, _, err := m.Open(0); err != nil {
76			t.Fatalf("Open: %v", err)
77		}
78		t.Cleanup(func() { _ = m.Close() })
79		return m, buf
80	}
81	
82	// warnCount reports how many WARN-level JSON records appear in s.
83	func warnCount(s string) int {
84		return strings.Count(s, `"level":"WARN"`)
85	}
86	
87	// TestOpenWarnsOnUnresolvableForcedDeviceBind is the D53 layer-(a) acceptance check at
88	// Open's call site: a boot-time path configured bind="device" whose source address
89	// resolves to NO interface (unassignableSource — RFC 5737 TEST-NET-1, present on no
90	// real host) makes Open's planPathBinds/selectForcedDeviceBind fallback SILENT
91	// pre-D53. It must now log exactly ONE WARN naming the path and the (empty, since
92	// unresolvable) interface. FAILS on the pre-D53 code, which never calls
93	// warnForcedDeviceUnresolvable.
94	func TestOpenWarnsOnUnresolvableForcedDeviceBind(t *testing.T) {
95		psk := testKey(t, 0xD1)
96		paths := []config.Path{
97			{Name: "forced-unresolvable", SourceAddr: netip.MustParseAddr(unassignableSource), Bind: config.BindModeDevice},
