101	
102		got := buf.String()
103		if n := warnCount(got); n != 1 {
104			t.Fatalf("WARN count = %d, want 1; log:\n%s", n, got)
105		}
106		if !strings.Contains(got, `"path":"forced-unresolvable"`) {
107			t.Fatalf("WARN does not name the path; log:\n%s", got)
108		}
109		if !strings.Contains(got, `"interface":""`) {
110			t.Fatalf("WARN does not name the (empty, unresolvable) interface; log:\n%s", got)
111		}
112	}
113	
114	// TestAddPathWarnsOnUnresolvableForcedDeviceBind is the D53 layer-(a) acceptance check
115	// at AddPath's call site (a runtime path admission, distinct from Open's), driven via
