136			t.Fatalf("WARN count = %d, want 1; log:\n%s", n, got)
137		}
138		if !strings.Contains(got, `"path":"forced-unresolvable"`) {
139			t.Fatalf("WARN does not name the path; log:\n%s", got)
140		}
141	}
